// Lookup with interpolation (exactly as Java does it)
function tLookup(arr, x) {
  let i = Math.floor(x);
  if (i < 0) i = 0;
  if (i >= arr.length - 1) return arr[arr.length - 1] || 0;
  let A = arr[i] || 0;
  let B = arr[i + 1] || 0;
  return A - (A - B) * ModFDiv(x, 1);
}

// ======== UTILITY FUNCTIONS (exact from Fungsi.java) ========
function ModFDiv(d, d1) { return d - d1 * Math.floor(d / d1); }
function Rad(deg) { return deg * (Math.atan(1) / 45); }
function Deg(rad) { return rad * (45 / Math.atan(1)); }
function SinA(d) { return Math.sin(Rad(d)); }
function CosA(d) { return Math.cos(Rad(d)); }
function TanA(d) { return Math.tan(Rad(d)); }
function Asn(n) { return Math.abs(n)===1 ? (2*Math.atan(1))*n : Math.atan(n/Math.sqrt(-n*n+1)); }
function Acs(n) { return Math.abs(n)===1 ? (2*Math.atan(1))*Math.abs(1-n) : Math.atan(-n/Math.sqrt(-n*n+1))+2*Math.atan(1); }
function AskRound0(d) { let A=Math.floor(d),B=(d-A)*1,C=Math.floor(B),D=B-C; return A+(C+(D>0.5?1:0))/1; }
function AskRound2(d) { let A=Math.floor(d),B=(d-A)*1000,C=Math.floor(B),D=B-C; return A+(C+(D>0.5?1:0))/1000; }

function DeltaT(tgl,bln,thn) {
  const y=thn+(bln-1)/12+tgl/365;
  if(y<-500){let u=(y-1820)/100;return -20+32*u*u;}
  else if(y<1986){let t=y-1975;return 45.45+1.067*t-t*t/260-t*t*t/718;}
  else if(y<2005){let t=y-2000;return 63.86+0.3345*t-0.060374*t*t+0.0017275*t*t*t+0.000651814*t*t*t*t+0.00002373599*t*t*t*t*t;}
  else if(y<2050){let t=y-2000;return 62.92+0.32217*t+0.005589*t*t;}
  else if(y<2150){return -20+32*Math.pow((y-1820)/100,2)-0.5628*(2150-y);}
  else{let u=(y-1820)/100;return -20+32*u*u;}
}

function JdToTgl(JD) {
  let Z=Math.floor(JD),F=JD-Z,A,AA;
  if(Z<2299161)A=Z;else{AA=Math.floor((Z-1867216.25)/36524.25);A=Z+1+AA-Math.floor(AA/4);}
  let B=A+1524,C=Math.floor((B-122.1)/365.25),D=Math.floor(365.25*C),e=Math.floor((B-D)/30.6001);
  let tgl=Math.floor(B-D-Math.floor(30.6001*e)),M,Y;
  if(e>13)M=e-13;else M=e-1;
  if(M<3)Y=C-4715;else Y=C-4716;
  let hari=ModFDiv(JD+16,7),pasr=ModFDiv(JD+16,5);
  return [0,tgl,M,Y,hari,pasr];
}

