const DM_DTK_M=[0,0,0,0,0,0.0001,0.0001,0.0001,0.0001,0.0001,0.0001,0.0001,0.0001,0.0001,0.0002,0.0002,0.0002,0.0002,0.0002,0.0002,0.0002,0.0002,0.0003,0.0003,0.0003,0.0003,0.0003,0.0003,0.0003,0.0003,0.0003,0.0004,0.0004,0.0004,0.0004,0.0004,0.0004,0.0004,0.0004,0.0004,0.0005,0.0005,0.0005,0.0005,0.0005,0.0005,0.0005,0.0005,0.0005,0.0006,0.0006,0.0006,0.0006,0.0006,0.0006,0.0006,0.0006,0.0007,0.0007,0.0007,0.0007];
// Menit Data Matahari (index 0-60)
const DM_MNT_S=[0,0.0007,0.0014,0.0021,0.0027,0.0034,0.0041,0.0048,0.0055,0.0062,0.0068,0.0075,0.0082,0.0089,0.0096,0.0103,0.011,0.0116,0.0123,0.013,0.0137,0.0144,0.0151,0.0157,0.0164,0.0171,0.0178,0.0185,0.0192,0.0198,0.0205,0.0212,0.0219,0.0226,0.0233,0.024,0.0246,0.0253,0.026,0.0267,0.0274,0.0281,0.0287,0.0294,0.0301,0.0308,0.0315,0.0322,0.0329,0.0335,0.0342,0.0349,0.0356,0.0363,0.037,0.0376,0.0383,0.039,0.0397,0.0404,0.0411];
const DM_MNT_M=[0,0.0007,0.0014,0.0021,0.0027,0.0034,0.0041,0.0048,0.0055,0.0062,0.0068,0.0075,0.0082,0.0089,0.0096,0.0103,0.011,0.0116,0.0123,0.013,0.0137,0.0144,0.0151,0.0157,0.0164,0.0171,0.0178,0.0185,0.0192,0.0198,0.0205,0.0212,0.0219,0.0226,0.0233,0.024,0.0246,0.0253,0.026,0.0267,0.0274,0.0281,0.0287,0.0294,0.0301,0.0308,0.0315,0.0322,0.0329,0.0335,0.0342,0.0349,0.0356,0.0363,0.037,0.0376,0.0383,0.039,0.0397,0.0404,0.0411];

function hitungAwalBulan(bln, thn, ltDrj, ltMnt, ltDtk, btDrj, btMnt, btDtk, Tt, Tz) {
  // Jika derajat lintang negatif (LS), menit dan detik otomatis ikut negatif
  const latSign = ltDrj < 0 ? -1 : 1;
  ltMnt = latSign * Math.abs(ltMnt);
  ltDtk = latSign * Math.abs(ltDtk);
  let Lt = ltDrj + ltMnt/60 + ltDtk/3600;
  let Bt = btDrj + btMnt/60 + btDtk/3600;
  
  let ThnM, BlnM;
  if(bln<2){ThnM=thn-1;BlnM=12;}else{ThnM=thn;BlnM=bln-1;}
  let ThnMj=Math.floor(ThnM/30)*30;
  let ThnMb=ThnM-ThnMj;

  // --- IJTIMAK ---
  let AlamahA=(IJT_MAJ[ThnMj]||IJT_MAJ[1440])[1];
  let AlamahB=IJT_MAB[ThnMb][1];
  let AlamahC=IJT_BLN[BlnM][1];
  let AlamahD=AlamahA+AlamahB+AlamahC;

  let AlhishohA=(IJT_MAJ[ThnMj]||IJT_MAJ[1440])[2];
  let AlhishohB=IJT_MAB[ThnMb][2];
  let AlhishohC=IJT_BLN[BlnM][2];
  let AlhishohD=ModFDiv(AlhishohA+AlhishohB+AlhishohC,360);

  let AlkhoshohA=(IJT_MAJ[ThnMj]||IJT_MAJ[1440])[3];
  let AlkhoshohB=IJT_MAB[ThnMb][3];
  let AlkhoshohC=IJT_BLN[BlnM][3];
  let AlkhoshohD=ModFDiv(AlkhoshohA+AlkhoshohB+AlkhoshohC,360);

  let AlmarkazA=(IJT_MAJ[ThnMj]||IJT_MAJ[1440])[4];
  let AlmarkazB=IJT_MAB[ThnMb][4];
  let AlmarkazC=IJT_BLN[BlnM][4];
  let AlmarkazD=ModFDiv(AlmarkazA+AlmarkazB+AlmarkazC,360);

  let D1=AlmarkazD,D2=ModFDiv(AlmarkazD*2,360),D3=AlkhoshohD,D4=ModFDiv(AlkhoshohD*2,360);
  let D5=ModFDiv(AlmarkazD+AlkhoshohD,360),D6=ModFDiv(AlmarkazD-AlkhoshohD,360);
  let D7=ModFDiv(AlhishohD*2,360),D8=ModFDiv(AlhishohD*2-AlkhoshohD,360);

  let Tk1=tLookup(IJT_Tk1,D1),Tk2=tLookup(IJT_Tk2,D2),Tk3=tLookup(IJT_Tk3,D3),Tk4=tLookup(IJT_Tk4,D4);
  let Tk5=tLookup(IJT_Tk5,D5),Tk6=tLookup(IJT_Tk6,D6),Tk7=tLookup(IJT_Tk7,D7),Tk8=tLookup(IJT_Tk8,D8);
  let Tk=Tk1+Tk2+Tk3+Tk4+Tk5+Tk6+Tk7+Tk8;

  let AM=AlamahD+Tk+0.5;
  let am=AM-1;
  let AmWib=AM+Tz/24;
  let TglMs=JdToTgl(AmWib)[1],BlnMs=JdToTgl(AmWib)[2],ThnMs=JdToTgl(AmWib)[3];
  let deltaT=DeltaT(TglMs,BlnMs,ThnMs);
  let hr=JdToTgl(AmWib)[4],ps=JdToTgl(AmWib)[5];

  let JDUT=AM-deltaT/86400;
  let TglUt=JdToTgl(JDUT)[1],BlnUt=JdToTgl(JDUT)[2],ThnUt=JdToTgl(JDUT)[3];
  let hrUt=JdToTgl(JDUT)[4],psUt=JdToTgl(JDUT)[5];
  let JamUt=(JDUT-Math.floor(JDUT))*24;

  let JDWD=JDUT+Tz/24;
  let TglWd=JdToTgl(JDWD)[1],BlnWd=JdToTgl(JDWD)[2],ThnWd=JdToTgl(JDWD)[3];
  let hrWd=JdToTgl(JDWD)[4],psWd=JdToTgl(JDWD)[5];
  let JamWd=(JDWD-Math.floor(JDWD))*24;

  let KetJam=Tz==7?"WIB":Tz==8?"WITA":Tz==9?"WIT":"(GMT+"+Tz+")";

  // --- DATA MATAHARI ---
  let majM=DM_MAJ[ThnMj]||DM_MAJ[1440], mabM=DM_MAB[ThnMb]||DM_MAB[0], blnDM=DM_BLN[BlnM]||DM_BLN[1];
  let JH1=ModFDiv((majM[2]||0)+(mabM[2]||0)+(blnDM[2]||0),7);
  let Kurang=ModFDiv(AskRound0(Math.floor(hrWd)-JH1),7);
  let Yaum;
  if(Kurang==1)Yaum=29;else if(Kurang==2)Yaum=30;else if(Kurang==6)Yaum=27;else if(Kurang==7||Kurang==0)Yaum=28;else Yaum=30;
  let yaumM=DM_YM[Yaum]||DM_YM[29];
  let mIjt=ModFDiv((majM[5]||0)+(mabM[5]||0)+(blnDM[5]||0)+(yaumM[5]||0),360);

  // Deklinasi & EoT from exact tables
  let dekKey=Math.floor(TglWd)+NmBlnM(BlnWd);
  let d1=DEK_TABLE[dekKey]||0;
  let e1=EOT_TABLE[dekKey]||0;

  let Sdm=0.267/(1-0.017*CosA(mIjt));
  let Dip=1.76/60*Math.sqrt(Tt);
  let hm=-(Sdm+34.5/60+Dip);
  let tm1=Deg(Acs(-TanA(Lt)*TanA(d1)+SinA(hm)/CosA(Lt)/CosA(d1)));
  let GrbLmt=tm1/15+12-e1;
  let GrbLmt1=AskRound0(GrbLmt*3600)/3600;
  let JamG=Math.floor(GrbLmt1);
  let MenitG=Math.floor((GrbLmt1-JamG)*60);
  let DetikG=AskRound0((((GrbLmt1-JamG)*60)-MenitG)*60);

  // Wasat Syams sums
  let Sa=majM[4]||0,Sb=mabM[4]||0,Sc=blnDM[4]||0,Sd=yaumM[4]||0;
  let Se=DM_JAM_S[JamG]||0,Sf=(DM_MNT_S[MenitG]||0),Sg=(DM_DTK_S[DetikG]||0);
  let ma_=majM[5]||0,mb_=mabM[5]||0,mc_=blnDM[5]||0,md_=yaumM[5]||0;
  let me_=DM_JAM_M[JamG]||0,mf_=(DM_MNT_M[MenitG]||0),mg_=(DM_DTK_M[DetikG]||0);
  let Qa=majM[6]||23.44,Qb=mabM[6]||0,Qc=blnDM[6]||0,Qd=yaumM[6]||0,Qe=0,Qf=0,Qg=0;

  let Sh=ModFDiv(Sa+Sb+Sc+Sd+Se+Sf+Sg,360);
  let mh=ModFDiv(ma_+mb_+mc_+md_+me_+mf_+mg_,360);
  let Qh=Qa+Qb+Qc+Qd+Qe+Qf+Qg;

  // FT
  let BtSampang=113+15/60;
  let FT=(BtSampang-Bt)/15;
  let FT1=AskRound0(FT*3600)/3600;
  let FT2=Math.abs(FT1);
  let JamF=Math.floor(FT2);
  let MenitF=Math.floor((FT2-JamF)*60);
  let DetikF=AskRound0((((FT2-JamF)*60)-MenitF)*60);

  let Si=DM_JAM_S[JamF]||0,mi=DM_JAM_M[JamF]||0;
  let Sj=(DM_MNT_S[MenitF]||0),mj=(DM_MNT_M[MenitF]||0);
  let Sk=(DM_DTK_S[DetikF]||0),mk=(DM_DTK_M[DetikF]||0);
  let Si1,mi1,Sj1,mj1,Sk1,mk1;
  if(FT<0){Si1=-Si;mi1=-mi;Sj1=-Sj;mj1=-mj;Sk1=-Sk;mk1=-mk;}
  else{Si1=Si;mi1=mi;Sj1=Sj;mj1=mj;Sk1=Sk;mk1=mk;}
  let Sm=ModFDiv(Sh+Si1+Sj1+Sk1,360);
  let mm=ModFDiv(mh+mi1+mj1+mk1,360);

  // Ta'dil Syams
  let DM1=mm,DM2=ModFDiv(mm*2,360);
  let Tks1=tLookup(DM_Ts1,DM1),Tks2=tLookup(DM_Ts2,DM2);
  let Ts=ModFDiv(Sm+Tks1+Tks2,360);
  let Ms=Deg(Asn(SinA(Ts)*SinA(Qh)));
  let Krm=Deg(Acs(CosA(Ts)/CosA(Ms)));
  let Arm=Ts>180?360-Krm:Krm;
  let eot=(Sm-Arm)/15;
  if(eot>12)eot=eot-24;

  let R1=tLookup(DM_TkR1,DM1),R2=tLookup(DM_TkR2,DM2);
  let R=1.00014+R1+R2;
  let Sdm2=(15/60+59.63/3600)/R;
  let hm2=-(Sdm2+34.5/60+Dip);
  let tm2=Deg(Acs(-TanA(Lt)*TanA(Ms)+SinA(hm2)/CosA(Lt)/CosA(Ms)));
  let GrbM=12-eot+((Tz*15)-Bt+tm2)/15;
  let Azm=270+Deg(Math.atan(-SinA(Lt)/TanA(tm2)+CosA(Lt)*TanA(Ms)/SinA(tm2)));

  // --- DATA BULAN ---
  let majB=DB_MAJ[ThnMj]||DB_MAJ[1440],mabB=DB_MAB[ThnMb]||DB_MAB[0],blnDB=DB_BLN[BlnM]||DB_BLN[1];
  let yaumB=DB_YM[Yaum]||DB_YM[29];

  // Sums with Jam/Menit/Detik Ghurub
  let Mbh=ModFDiv(majB[1]+mabB[1]+blnDB[1]+yaumB[1]+(DB_JAM_M[JamG]||0)+(DB_MNT_M[MenitG]||0)+(DB_DTK_M[DetikG]||0),360);
  let Abh=ModFDiv(majB[2]+mabB[2]+blnDB[2]+yaumB[2]+(DB_JAM_A[JamG]||0)+(DB_MNT_A[MenitG]||0)+(DB_DTK_A[DetikG]||0),360);
  let Nbh=ModFDiv(majB[3]+mabB[3]+blnDB[3]+yaumB[3]+(DB_JAM_N[JamG]||0)+(DB_MNT_N[MenitG]||0)+(DB_DTK_N[DetikG]||0),360);
  let Dbh=ModFDiv(majB[4]+mabB[4]+blnDB[4]+yaumB[4]+(DB_JAM_D[JamG]||0)+(DB_MNT_D[MenitG]||0)+(DB_DTK_D[DetikG]||0),360);
  let STh=ModFDiv(majB[5]+mabB[5]+blnDB[5]+yaumB[5]+(DB_JAM_ST[JamG]||0)+(DB_MNT_ST[MenitG]||0)+(DB_DTK_ST[DetikG]||0),360);

  // FT correction for bulan
  let Mbi1,Abi1,Nbi1,Dbi1,STi1,Mbj1,Abj1,Nbj1,Dbj1,STj1,Mbk1,Abk1,Nbk1,Dbk1,STk1;
  let Mbi=DB_JAM_M[JamF]||0,Abi=DB_JAM_A[JamF]||0,Nbi=DB_JAM_N[JamF]||0,Dbi=DB_JAM_D[JamF]||0,STi=DB_JAM_ST[JamF]||0;
  let Mbj=(DB_MNT_M[MenitF]||0),Abj=(DB_MNT_A[MenitF]||0),Nbj=(DB_MNT_N[MenitF]||0),Dbj=(DB_MNT_D[MenitF]||0),STj=(DB_MNT_ST[MenitF]||0);
  let Mbk=(DB_DTK_M[DetikF]||0),Abk=(DB_DTK_A[DetikF]||0),Nbk=(DB_DTK_N[DetikF]||0),Dbk=(DB_DTK_D[DetikF]||0),STk=(DB_DTK_ST[DetikF]||0);
  if(FT<0){Mbi1=-Mbi;Abi1=-Abi;Nbi1=-Nbi;Dbi1=-Dbi;STi1=-STi;Mbj1=-Mbj;Abj1=-Abj;Nbj1=-Nbj;Dbj1=-Dbj;STj1=-STj;Mbk1=-Mbk;Abk1=-Abk;Nbk1=-Nbk;Dbk1=-Dbk;STk1=-STk;}
  else{Mbi1=Mbi;Abi1=Abi;Nbi1=Nbi;Dbi1=Dbi;STi1=STi;Mbj1=Mbj;Abj1=Abj;Nbj1=Nbj;Dbj1=Dbj;STj1=STj;Mbk1=Mbk;Abk1=Abk;Nbk1=Nbk;Dbk1=Dbk;STk1=STk;}

  let Mbm=ModFDiv(Mbh+Mbi1+Mbj1+Mbk1,360);
  let Abm=ModFDiv(Abh+Abi1+Abj1+Abk1,360);
  let Nbm=ModFDiv(Nbh+Nbi1+Nbj1+Nbk1,360);
  let Dbm=ModFDiv(Dbh+Dbi1+Dbj1+Dbk1,360);
  let STm=ModFDiv(STh+STi1+STj1+STk1,360);

  // Dalil Bulan
  let DB1=Abm,DB2=ModFDiv(Dbm*2-Abm,360),DB3=ModFDiv(Dbm*2,360),DB4=ModFDiv(Abm*2,360);
  let DB5=ModFDiv(mm,360),DB6=ModFDiv(Nbm*2,360),DB7=ModFDiv(Dbm*2-Abm*2,360);
  let DB8=ModFDiv(Dbm*2-mm-Abm,360),DB9=ModFDiv(Dbm*2+Abm,360);

  let TB1=tLookup(KB_TkB1,DB1),TB2=tLookup(KB_TkB2,DB2),TB3=tLookup(KB_TkB3,DB3);
  let TB4=tLookup(KB_TkB4,DB4),TB5=tLookup(KB_TkB5,DB5),TB6=tLookup(KB_TkB6,DB6);
  let TB7=tLookup(KB_TkB7,DB7),TB8=tLookup(KB_TkB8,DB8),TB9=tLookup(KB_TkB9,DB9);
  let Tkb=TB1+TB2+TB3+TB4+TB5+TB6+TB7+TB8+TB9;
  let Tq=ModFDiv(Mbm+Tkb,360);

  // Ardul Qomar
  let DC1=Nbm,DC2=ModFDiv(Abm+Nbm,360),DC3=ModFDiv(Abm-Nbm,360),DC4=ModFDiv(Dbm*2-Nbm,360);
  let TC1=tLookup(KB_TkC1,DC1),TC2=tLookup(KB_TkC2,DC2),TC3=tLookup(KB_TkC3,DC3),TC4=tLookup(KB_TkC4,DC4);
  let Aq=TC1+TC2+TC3+TC4;

  let DekB=Deg(Asn(SinA(Aq)*CosA(Qh)+CosA(Aq)*SinA(Qh)*SinA(Tq)));
  let Krb=Deg(Acs(CosA(Tq)*CosA(Aq)/CosA(DekB)));
  let Arb=Tq>180?360-Krb:Krb;

  // Jarak Bulan
  let DR1=Abm,DR2=ModFDiv(Dbm*2-Abm,360),DR3=ModFDiv(Dbm*2,360),DR4=ModFDiv(Abm*2,360);
  let TR1=tLookup(KB2_TkRb1,DR1),TR2=tLookup(KB2_TkRb2,DR2),TR3=tLookup(KB2_TkRb3,DR3),TR4=tLookup(KB2_TkRb4,DR4);
  let Rb=385000.56+TR1+TR2+TR3+TR4;

  let Hpb=Deg(Asn(6378.14/Rb)),Sdb=0.272476*Hpb;
  let tb=ModFDiv(STm-Arb+Bt,360);
  let hcH=Deg(Asn(SinA(Lt)*SinA(DekB)+CosA(Lt)*CosA(DekB)*CosA(tb)));
  let Ref=0.0167/TanA(hcH+7.31/(hcH+4.4));
  let P=Hpb*CosA(hcH);
  let hT=hcH-P;
  let hL;
  if(hT<0)hL=hT;else hL=hT+Ref+Dip-Sdb;
  let Azb=270+Deg(Math.atan(-SinA(Lt)/TanA(tb)+CosA(Lt)*TanA(DekB)/SinA(tb)));
  let Elo=Deg(Acs(CosA(Tq-Ts)*CosA(Aq)));

  let DI=180-Elo-0.1468*((1-0.0549*SinA(Abm))/(1-0.0167*SinA(mm)))*SinA(Elo);
  let Nh_raw=tLookup(KB2_TkNh,DI);
  let Nh=Nh_raw*100;
  let Lm=hcH/15;
  let GrbB=GrbM+Lm;
  let Umur=GrbM-JamWd;

  // Awal Bulan
  JDWD=JDUT+Tz/24;
  let JDA;
  if(hL>3&&Elo>6.4)JDA=JDWD+1;else JDA=JDWD+2;
  let aR=JdToTgl(JDA);

  return {bln,thn,ThnM,Lt,Bt,Tt,Tz,KetJam,ThnMj,ThnMb,BlnM,
    // Ijtimak intermediates
    AlamahA,AlamahB,AlamahC,AlamahD,
    AlhishohA,AlhishohB,AlhishohC,AlhishohD,
    AlkhoshohA,AlkhoshohB,AlkhoshohC,AlkhoshohD,
    AlmarkazA,AlmarkazB,AlmarkazC,AlmarkazD,
    D1,D2,D3,D4,D5,D6,D7,D8,
    Tk1,Tk2,Tk3,Tk4,Tk5,Tk6,Tk7,Tk8,Tk,
    AM,am,AmWib,TglMs,BlnMs,ThnMs,deltaT,
    JDUT,TglUt,BlnUt,ThnUt,hrUt:Math.floor(hrUt),psUt:Math.floor(psUt),JamUt,
    JDWD,TglWd,BlnWd,ThnWd,hrWd:Math.floor(hrWd),psWd:Math.floor(psWd),JamWd,
    // Matahari intermediates
    Yaum,Kurang,mIjt,dekKey,d1,e1,Sdm,Dip,hm,tm1,GrbLmt,GrbLmt1,JamG,MenitG,DetikG,
    Sa,Sb,Sc,Sd,Se,Sf,Sg,Sh,
    ma_,mb_,mc_,md_,me_,mf_,mg_,mh,
    Qa,Qb,Qc,Qd,Qe,Qf,Qg,Qh,
    FT,FT1,FT2,JamF,MenitF,DetikF,
    Si,mi,Sj,mj,Sk,mk,Si1,mi1,Sj1,mj1,Sk1,mk1,
    Sm,mm,DM1,DM2,Tks1,Tks2,Ts,Ms,Krm,Arm,eot,
    R1,R2,R,Sdm2,hm2,tm2,
    // Bulan intermediates  
    Mba:majB[1],Abb:mabB[2],Mbb:mabB[1],Abc:blnDB[2],Mbc:blnDB[1],Abd:yaumB[2],Mbd:yaumB[1],
    Aba:majB[2],Nba:majB[3],Dba:majB[4],STa:majB[5],
    Nbb:mabB[3],Dbb:mabB[4],STb:mabB[5],
    Nbc:blnDB[3],Dbc:blnDB[4],STc:blnDB[5],
    Nbd:yaumB[3],Dbd:yaumB[4],STd:yaumB[5],
    Mbe:DB_JAM_M[JamG]||0,Abe:DB_JAM_A[JamG]||0,Nbe:DB_JAM_N[JamG]||0,Dbe:DB_JAM_D[JamG]||0,STe:DB_JAM_ST[JamG]||0,
    Mbf:(DB_MNT_M[MenitG]||0),Abf:(DB_MNT_A[MenitG]||0),Nbf:(DB_MNT_N[MenitG]||0),Dbf:(DB_MNT_D[MenitG]||0),STf:(DB_MNT_ST[MenitG]||0),
    Mbg:(DB_DTK_M[DetikG]||0),Abg:(DB_DTK_A[DetikG]||0),Nbg:(DB_DTK_N[DetikG]||0),Dbg:(DB_DTK_D[DetikG]||0),STg:(DB_DTK_ST[DetikG]||0),
    Mbh,Abh,Nbh,Dbh,STh,
    Mbi,Abi,Nbi,Dbi,STi:STi,Mbj,Abj,Nbj,Dbj,STj,Mbk,Abk,Nbk,Dbk,STk,
    Mbi1,Abi1,Nbi1,Dbi1,STi1,Mbj1,Abj1,Nbj1,Dbj1,STj1,Mbk1,Abk1,Nbk1,Dbk1,STk1,
    Mbm,Abm,Nbm,Dbm,STm,
    DB1,DB2,DB3,DB4,DB5,DB6,DB7,DB8,DB9,
    TB1,TB2,TB3,TB4,TB5,TB6,TB7,TB8,TB9,Tkb,
    DC1,DC2,DC3,DC4,TC1,TC2,TC3,TC4,
    DR1,DR2,DR3,DR4,TR1,TR2,TR3,TR4,
    // Results
    ijtTgl:TglWd,ijtBln:BlnWd,ijtThn:ThnWd,ijtHari:NmHr(Math.floor(hrWd)),ijtPasar:NmPs(Math.floor(psWd)),
    ijtJam:JamWd,ijtJamStr:Hms0(JamWd),
    GrbM,GrbMStr:Hms0(GrbM),Azm,AzmStr:DDDMMSS0(Azm),AzmDiff:DDMMSS1(Azm-270),
    hcH,hcHStr:DDMMSS1(hcH),hT,hTStr:DDMMSS1(hT),hL,hLStr:DDMMSS1(hL),
    Elo,EloStr:DDMMSS1(Elo),Azb,AzbStr:DDDMMSS0(Azb),AzbDiff:DDMMSS1(Azb-270),
    AzDiff:DDDMMSS0(Azb-Azm),tb,
    Nh:AskRound2(Nh),Umur,UmurStr:Hms1(Umur),Lm,LmStr:Hms1(Lm),
    GrbB,GrbBStr:Hms0(GrbB),Hpb,Sdb,P,Tq,Arb,Aq,DekB,Rb,Ref,DI,
    awalHari:NmHr(Math.floor(aR[4])),awalPasar:NmPs(Math.floor(aR[5])),
    awalTgl:aR[1],awalBln:aR[2],awalThn:aR[3],awalBlnNm:NmBlnM(aR[2])
  };
}

